transforms.result:
header {
  --header-padding: 4rem;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: flex-start;
  padding-top: var(--header-padding);
  padding-bottom: var(--header-padding);
  padding-left: 0rem;
}

.menu {
  display: flex;
}

.menu:hover {
  color: #7c3aed;
}

@media (min-width: 640px) {
  .menu {
    display: none;
  }
}

.overlay {
  position: absolute;
  top: calc(100% + 0.5rem);
  right: 0;
  background-color: rgba(255, 255, 255, 0.7);
  border: 1px solid #e5e7eb;
  border-radius: 0.375rem;
  padding: 1.5rem;
  font-size: 1.125rem;
  line-height: 1.75rem;
  font-weight: 500;
  transition: all 250ms;
  perspective: 2000px;
  transform-origin: top;
  backdrop-filter: blur(20px);
  will-change: opacity, transform;
}

.overlay:not(.show) {
  opacity: 0;
  transform: translateY(-10px) rotateY(-8deg) rotateX(-20deg);
  pointer-events: none;
}

@media (min-width: 640px) {
  .overlay {
    display: none;
  }
}

.dark .overlay {
  border-color: #374151;
  background-color: rgba(17, 24, 39, 0.7);
}

.main-nav {
  display: none;
  font-size: 1.25rem;
  line-height: 1.75rem;
  font-weight: 500;
}

@media (min-width: 640px) {
  .main-nav {
    display: flex;
  }
}

